proof_block:
// The spec `SingleDelivery::send_single_message` is `pub open spec` and is a
// (deterministic) function of (pre, m, dst): the body branches on whether
// `new_seqno > params.max_seqno`, and in each branch fully pins down the unique
// (post, sm) pair. The det check's two `send_single_message(...)` hypotheses
// (one per run) sit under disjoint `match r1`/`match r2` arms and z3 never
// lines them up. We hand it a forall lemma that maps every satisfying
// (post, sm) for the shared (pre_self_@, m@, dst@) to the unique canonical
// pair; the trigger on `send_single_message(...)` then fires on both runs.
let params = AbstractParameters::static_params();
let old_ack_state = ack_state_lookup(dst@, pre_self_@.send_state);
let new_seqno = old_ack_state.num_packets_acked + old_ack_state.un_acked.len() + 1;
let expected_msg: SingleMessage<Message> =
    SingleMessage::Message { seqno: new_seqno, m: m@, dst: dst@ };
let expected_post: SingleDelivery<Message> = SingleDelivery {
    send_state: pre_self_@.send_state.insert(
        dst@,
        AckState {
            un_acked: old_ack_state.un_acked.push(expected_msg),
            ..old_ack_state
        },
    ),
    ..pre_self_@
};

assert forall|p: SingleDelivery<Message>, sm: Option<SingleMessage<Message>>|
    #[trigger] SingleDelivery::send_single_message(pre_self_@, p, m@, dst@, sm, params)
    implies (if new_seqno > params.max_seqno {
        p == pre_self_@ && sm is None
    } else {
        sm == Some(expected_msg) && p == expected_post
    }) by {
    // `send_single_message` is `pub open spec`; z3 unfolds the body and reads
    // off the unique (p, sm) in each branch.
};
